"""Диалог встроенной справки."""from __future__ import annotationsfrom pathlib import Pathfrom PySide6.QtCore import QUrlfrom PySide6.QtGui import QDesktopServices, QTextCursorfrom PySide6.QtWidgets import (    QDialog, QDialogButtonBox, QTextBrowser, QVBoxLayout, QWidget,)class HelpDialog(QDialog):    def __init__(self, html_path: Path,                 parent: QWidget | None = None) -> None:        super().__init__(parent)        self.setWindowTitle("SAFR — Руководство пользователя")        self.resize(900, 700)        self._browser = QTextBrowser(self)        self._browser.setOpenExternalLinks(False)        self._browser.setOpenLinks(True)        self._browser.anchorClicked.connect(self._on_anchor_clicked)        buttons = QDialogButtonBox(QDialogButtonBox.Close, parent=self)        buttons.rejected.connect(self.reject)        buttons.accepted.connect(self.accept)        layout = QVBoxLayout(self)        layout.addWidget(self._browser)        layout.addWidget(buttons)        self._load(html_path)    def _load(self, html_path: Path) -> None:        if not html_path.is_file():            self._browser.setHtml(                "<h2>Справка недоступна</h2>"                f"<p>Не удалось найти файл руководства по пути:<br>"                f"<code>{html_path}</code></p>"            )            return        try:            text = html_path.read_text(encoding="utf-8")        except OSError as e:            self._browser.setHtml(                "<h2>Не удалось прочитать справку</h2>"                f"<p>{type(e).__name__}: {e}</p>"            )            return        self._browser.setSearchPaths([str(html_path.parent)])        self._browser.setHtml(text)        # Перемотка в начало документа. Используем публичный метод QTextBrowser,        # он работает одинаково и в PySide6, и в PyQt, без обращения к        # enum-значениям QTextCursor.        self._browser.moveCursor(QTextCursor.MoveOperation.Start)    def _on_anchor_clicked(self, url: QUrl) -> None:        if url.scheme() in ("http", "https", "mailto"):            QDesktopServices.openUrl(url)            return        self._browser.setSource(url)